import 'dart:typed_data'; import 'package:flutter/material.dart'; class ImageUtils { static ImageProvider? urlToProvider(String? url) { if (url == null || url.isEmpty) return null; return NetworkImage(url); } static String? getAvatarInitials(String? name) { if (name == null || name.isEmpty) return null; final parts = name.trim().split(' '); return parts.length >= 2 ? '${parts[0][0]}${parts[1][0]}'.toUpperCase() : parts[0][0].toUpperCase(); } }
